#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=12;
void exgcd(int a,int b,int &x,int &y) {
	if(b==0) {
		x=1;
		y=0;
		return;
	}
	exgcd(b,a%b,x,y);
	int s=x;
	x=y;
	y=s-a/b*y;
}
long long n;
int m[maxn],a[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	int M=1,res=0;
	for(int i=1;i<=n;i++){
		cin>>m[i]>>a[i];
		M*=m[i];
	}
	for(int i=1;i<=n;i++){
		int s=M/m[i],x,y;
		exgcd(s,m[i],x,y);
		x=__int128(x%m[i]+m[i])%m[i];
		res=(res+__int128(a[i]*s)%M*x%M);
	}
	cout<<(res%M+M)%M;
	return 0;
}
